  "params": {
    "path": "/Users/lzz/Desktop/valorant_stats.html",
    "content": "<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>无畏契约 - 战绩分析中心</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background: linear-gradient(135deg, #0a0e27 0%, #1a1f3a 50%, #0f1729 100%);
            color: #e1e8ed;
            min-height: 100vh;
        }

        /* 顶部导航栏 */
        .navbar {
            background: rgba(15, 23, 41, 0.95);
            border-bottom: 2px solid #7f39fb;
            padding: 15px 40px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            position: sticky;
            top: 0;
            z-index: 1000;
            box-shadow: 0 4px 20px rgba(127, 57, 251, 0.15);
        }

        .logo {
            font-size: 24px;
            font-weight: 900;
            color: #7f39fb;
            letter-spacing: 2px;
            display: flex;
            align-items: center;
            gap: 10px;
        }

        .logo::before {
            content: '⚔️';
            font-size: 28px;
        }

        .nav-menu {
            display: flex;
            gap: 30px;
            list-style: none;
        }

        .nav-menu a {
            color: #e1e8ed;
            text-decoration: none;
            font-weight: 600;
            transition: all 0.3s ease;
            padding: 8px 12px;
            border-radius: 4px;
        }

        .nav-menu a:hover {
            color: #7f39fb;
            background: rgba(127, 57, 251, 0.1);
        }

        .nav-menu a.active {
            color: #7f39fb;
            border-bottom: 2px solid #7f39fb;
        }

        .user-info {
            display: flex;
            align-items: center;
            gap: 15px;
        }

        .user-avatar {
            width: 40px;
            height: 40px;
            border-radius: 50%;
            background: linear-gradient(135deg, #7f39fb, #0ea5e9);
            display: flex;
            align-items: center;
            justify-content: center;
            font-weight: bold;
            font-size: 18px;
        }

        /* 主容器 */
        .container {
            max-width: 1400px;
            margin: 40px auto;
            padding: 0 20px;
        }

        /* 用户头部信息区 */
        .user-header {
            background: linear-gradient(135deg, rgba(127, 57, 251, 0.1), rgba(14, 165, 233, 0.1));
            border: 2px solid #7f39fb;
            border-radius: 12px;
            padding: 30px;
            margin-bottom: 40px;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .user-basic-info h1 {
            font-size: 32px;
            margin-bottom: 10px;
            color: #7f39fb;
        }

        .user-basic-info p {
            color: #a0aec0;
            font-size: 14px;
        }

        .quick-stats {
            display: flex;
            gap: 30px;
        }

        .stat-item {
            text-align: center;
        }

        .stat-value {
            font-size: 28px;
            font-weight: 900;
            color: #7f39fb;
        }

        .stat-label {
            font-size: 12px;
            color: #a0aec0;
            margin-top: 5px;
            text-transform: uppercase;
        }

        /* 网格布局 */

